module SR_Latch(
    input SR_S,
    input R,
    output reg Q,
    output reg Qn
);
    always @ (SR_S or R) begin
        if (SR_S && !R) begin
            Q <= 1'b1;
            Qn <= 1'b0;
        end else if (!SR_S && R) begin
            Q <= 1'b0;
            Qn <= 1'b1;
        end else if (!SR_S && !R) begin
            // Maintain previous state
            Q <= Q;
            Qn <= Qn;
        end else begin
            // Invalid state: both SR_S and R should not be high
            // You can choose to handle this case as desired
        end
    end
endmodule
